items.configValue:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "PDF Content",
  "description": "A schema for the content of a generated PDF document.",
  "type": "object",
  "properties": {
    "title": {
      "description": "The main title of the document.",
      "type": "string"
    },
    "sections": {
      "description": "An array of sections, each with a title and content.",
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "title": {
            "description": "The title of the section.",
            "type": "string"
          },
          "content": {
            "description": "The content of the section.",
            "type": "string"
          }
        },
        "required": ["title", "content"]
      }
    }
  },
  "required": ["title", "sections"]
}
